import{_ as o,o as a,c as t,ai as n}from"./chunks/framework.CsYGeNYI.js";const s="/docs/assets/01-macos-warning.1S67uo4R.jpeg",i="/docs/assets/02-local-networks.CMVELAqU.jpeg",r="/docs/assets/03-security-notice.DusLxL_F.png",c="/docs/assets/04-choose-gateway.CHL1QHXV.png",l="/docs/assets/05-permissions.DwfAfjml.png",w=JSON.parse('{"title":"Onboarding (macOS App)","description":"","frontmatter":{"summary":"First-run onboarding flow for OpenSoul (macOS app)","read_when":["Designing the macOS onboarding assistant","Implementing auth or identity setup"],"title":"Onboarding (macOS App)","sidebarTitle":"Onboarding: macOS App"},"headers":[],"relativePath":"start/onboarding.md","filePath":"start/onboarding.md","lastUpdated":null}'),d={name:"start/onboarding.md"};function p(h,e,g,u,m,b){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="onboarding-macos-app" tabindex="-1"><a class="header-anchor" href="#onboarding-macos-app">#</a> Onboarding (macOS App)</h1><p>This doc describes the <strong>current</strong> first‑run onboarding flow. The goal is a smooth “day 0” experience: pick where the Gateway runs, connect auth, run the wizard, and let the agent bootstrap itself.</p><h3 id="approve-macos-warning" tabindex="-1"><a class="header-anchor" href="#approve-macos-warning">#</a> Approve macOS warning</h3><img src="'+s+'" alt=""><h3 id="approve-find-local-networks" tabindex="-1"><a class="header-anchor" href="#approve-find-local-networks">#</a> Approve find local networks</h3><img src="'+i+'" alt=""><h3 id="welcome-and-security-notice" tabindex="-1"><a class="header-anchor" href="#welcome-and-security-notice">#</a> Welcome and security notice</h3><img src="'+r+'" alt="Read the security notice displayed and decide accordingly"><blockquote><p><em>Read the security notice displayed and decide accordingly</em></p></blockquote><h3 id="local-vs-remote" tabindex="-1"><a class="header-anchor" href="#local-vs-remote">#</a> Local vs Remote</h3><img src="'+c+'" alt=""><p>Where does the <strong>Gateway</strong> run?</p><ul><li><strong>This Mac (Local only):</strong> onboarding can run OAuth flows and write credentials locally.</li><li><strong>Remote (over SSH/Tailnet):</strong> onboarding does <strong>not</strong> run OAuth locally; credentials must exist on the gateway host.</li><li><strong>Configure later:</strong> skip setup and leave the app unconfigured.</li></ul><blockquote><p><strong>Tip:</strong><strong>Gateway auth tip:</strong></p><ul><li>The wizard now generates a <strong>token</strong> even for loopback, so local WS clients must authenticate.</li><li>If you disable auth, any local process can connect; use that only on fully trusted machines.</li><li>Use a <strong>token</strong> for multi‑machine access or non‑loopback binds.</li></ul></blockquote><h3 id="permissions" tabindex="-1"><a class="header-anchor" href="#permissions">#</a> Permissions</h3><img src="'+l+'" alt="Choose what permissions do you want to give OpenSoul"><blockquote><p><em>Choose what permissions do you want to give OpenSoul</em></p></blockquote><p>Onboarding requests TCC permissions needed for:</p><ul><li>Automation (AppleScript)</li><li>Notifications</li><li>Accessibility</li><li>Screen Recording</li><li>Microphone</li><li>Speech Recognition</li><li>Camera</li><li>Location</li></ul><h3 id="cli" tabindex="-1"><a class="header-anchor" href="#cli">#</a> CLI</h3><blockquote><p><strong>Info:</strong> This step is optional</p></blockquote><p>The app can install the global <code>opensoul</code> CLI via npm/pnpm so terminal workflows and launchd tasks work out of the box.</p><h3 id="onboarding-chat-dedicated-session" tabindex="-1"><a class="header-anchor" href="#onboarding-chat-dedicated-session">#</a> Onboarding Chat (dedicated session)</h3><p>After setup, the app opens a dedicated onboarding chat session so the agent can introduce itself and guide next steps. This keeps first‑run guidance separate from your normal conversation. See <a href="/docs/start/bootstrapping">Bootstrapping</a> for what happens on the gateway host during the first agent run.</p>',24)])])}const _=o(d,[["render",p]]);export{w as __pageData,_ as default};
